protected:
    Array* arr;

    ArrayTest() {}
    ~ArrayTest() override {}

    void SetUp() override {
        // Just call the constructor directly, no need for MakeArray
        arr = new Array(10, 2, 30);
    }

    void TearDown() override {
        delete arr; // Make sure to uncomment this to avoid memory leaks
    }
};

TEST_F(ArrayTest, SetAndGetElement) {
    // Use the array operator[] correctly by dereferencing 'arr'
    (*arr)[4][1][2] = 100500;
